$string['rec_engagement_decline'] = 'This student typically disengages mid-semester. Schedule a proactive check-in around week 4-5 before the pattern repeats, and consider front-loading key support resources.';
$string['rec_feedback_neglect'] = 'This student rarely reviews feedback across their courses. Walk them through their feedback on the first graded assignment to model the habit, and consider making feedback review a prerequisite for the next submission.';
$string['rec_feedback_neglect_single'] = 'In their recent course, this student rarely reviewed feedback. Walk them through the feedback on their next graded assignment to model the habit, and watch whether the pattern repeats in upcoming courses.';
